let respostas = {};
let perguntasLista = [];

const form = document.getElementById("form");

let index = 0;

// GERAR FORMULÁRIO
for (let secao in estrutura) {
  let html = `<div class="secao"><h3>${secao}</h3>`;

  estrutura[secao].forEach(p => {
    perguntasLista.push(p);

    html += `
      <div class="pergunta">
        <div>${index + 1}. ${p}</div>

        <div class="botoes">
          <button data-id="${index}" data-val="C" onclick="responder(${index}, 'C')">C</button>
          <button data-id="${index}" data-val="NC" onclick="responder(${index}, 'NC')">NC</button>
          <button data-id="${index}" data-val="NA" onclick="responder(${index}, 'NA')">NA</button>
        </div>

        <textarea id="obs${index}" placeholder="Observação"></textarea>
        <div id="fotoContainer${index}" style="display:none; margin-top:10px;">
  
  <label style="background:#008000; color:#fff; padding:8px 12px; border-radius:8px; cursor:pointer;">
    📸 Anexar Imagem
    <input type="file" accept="image/*" capture="environment" 
           onchange="salvarFoto(event, ${index})" 
           style="display:none;">
  </label>

  <br>

  <img id="preview${index}" style="display:none; width:120px; margin-top:8px; border-radius:8px;">

</div>
      </div>
    `;
    index++;
  });

  html += `</div>`;
  form.innerHTML += html;
}
//FOTO
function salvarFoto(event, i) {
  const file = event.target.files[0];
  if (!file) return;

  const reader = new FileReader();

  reader.onload = function(e) {
    fotos[i] = e.target.result;

    const img = document.getElementById("preview" + i);
    img.src = fotos[i];
    img.style.display = "block";
  };

  reader.readAsDataURL(file);
}
// BOTÕES
function responder(i, valor) {
  respostas[i] = valor;

  const botoes = document.querySelectorAll(`[data-id="${i}"]`);
  botoes.forEach(btn => btn.classList.remove("selected", "C", "NC", "NA"));

  const btn = document.querySelector(`[data-id="${i}"][data-val="${valor}"]`);
  if (btn) btn.classList.add("selected", valor);

  const fotoDiv = document.getElementById("fotoContainer" + i);

if (valor === "NC") {
  fotoDiv.style.display = "block"; // aparece
} else {
  fotoDiv.style.display = "none";  // some
}
}

// CÁLCULO
let percentualFinal = 0;
let statusFinal = "";

function calcular() {
  let total = 0;
  let nc = 0;
  let c = 0;

  for (let i = 0; i < perguntasLista.length; i++) {
    if (respostas[i] && respostas[i] !== "NA") {
      total++;
      if (respostas[i] === "NC") nc++;
      if (respostas[i] === "C") c++;
    }
  }

  percentualFinal = (nc / total) * 100 || 0;

  if (percentualFinal > 20) statusFinal = "VERMELHO";
  else if (percentualFinal >= 10) statusFinal = "REGULAR";
  else statusFinal = "BOM";

  let cor = statusFinal === "VERMELHO" ? "vermelho" :
            statusFinal === "REGULAR" ? "amarelo" : "verde";

  document.getElementById("resultado").innerHTML = `
    <h3>RESULTADO</h3>
    <div class="resultado-item"><span>Questões avaliadas:</span><strong>${total}</strong></div>
    <div class="resultado-item"><span>Não conformes:</span><strong>${nc}</strong></div>
    <div class="resultado-item"><span>Conformes:</span><strong>${c}</strong></div>
    <div class="resultado-item"><span>Percentual:</span><strong>${percentualFinal.toFixed(2)}%</strong></div>
    <div class="resultado-item"><span>Status:</span><strong>${statusFinal}</strong></div>
    <div class="barra-container"><div class="barra ${cor}" style="width:${percentualFinal}%"></div></div>
  `;
}

// PDF
function gerarPDF() {
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF();

  let y = 10;

  // LOGO
  // LOGO CORRETA
try {
  doc.addImage(logoBase64, "PNG", 150, 5, 40, 20);
} catch (e) {
  console.log("Erro ao carregar logo");
}

  doc.setFontSize(12);
  doc.text("CHECK LIST - BOAS PRÁTICAS DE FABRICAÇÃO", 10, y);

  y += 8;

  const empresa = document.getElementById("empresa")?.value || "Não informado";
  

  doc.setFontSize(10);
  const setor = document.getElementById("setor")?.value || "Não informado";

  doc.text(`Setor: ${setor}`, 10, y);

  y += 6;
  doc.text(`Empresa: ${empresa}`, 10, y);

  y += 10;

  let numero = 1;

  for (let secao in estrutura) {
    doc.setFontSize(11);
    doc.text(secao.toUpperCase(), 10, y);
    y += 6;

    estrutura[secao].forEach((p) => {
      const resp = respostas[numero - 1] || "";
      const obs = document.getElementById("obs" + (numero - 1))?.value || "";

      if (y > 270) {
        doc.addPage();
        y = 10;
      }

      doc.setFontSize(10);
      const linhas = doc.splitTextToSize(`${numero}. ${p}`, 180);
      doc.text(linhas, 10, y);
      y += linhas.length * 5;

      let cor = [156, 163, 175];
      let texto = "NA";

      if (resp === "C") {
        cor = [34, 197, 94];
        texto = "C";
      } else if (resp === "NC") {
        cor = [239, 68, 68];
        texto = "NC";
      }

      doc.setFillColor(...cor);
      doc.rect(10, y, 25, 8, "F");

      doc.setTextColor(255, 255, 255);
      doc.text(texto, 17, y + 5);
      doc.setTextColor(0, 0, 0);

      y += 12;

      if (obs.trim() !== "") {
        const linhasObs = doc.splitTextToSize("Obs: " + obs, 170);
        doc.setFontSize(9);
        doc.text(linhasObs, 12, y);
        y += (linhasObs.length * 5) + 3;
      }

      // FOTO
if (fotos[numero - 1]) {

  if (y > 240) {
    doc.addPage();
    y = 20;
  }

  doc.addImage(fotos[numero - 1], "JPEG", 10, y, 60, 45);
  y += 50;
}

      doc.line(10, y, 200, y);
      y += 5;

      numero++;
    });

    y += 5;
  }

  y += 10;
  const alturaBlocoFinal = 100;
 
  if (y + alturaBlocoFinal > 270) {
  doc.addPage();
  y = 20;
}

  doc.setFontSize(10);
  doc.text(`Não conformidade: ${percentualFinal.toFixed(2)}%`, 10, y);

  y += 8;
  doc.setFontSize(12);
  // ===== TARJA DE RESULTADO =====
y += 5;

// define cor baseada no status
let corStatus = [34, 197, 94]; // verde padrão

if (statusFinal === "REGULAR") {
  corStatus = [245, 158, 11]; // amarelo
} else if (statusFinal === "VERMELHO") {
  corStatus = [239, 68, 68]; // vermelho
}

// fundo da tarja
doc.setFillColor(...corStatus);
doc.rect(10, y, 190, 12, "F");

// texto dentro da tarja
doc.setTextColor(255, 255, 255);
doc.setFontSize(12);
doc.text(`RESULTADO FINAL: ${statusFinal}`, 105, y + 8, { align: "center" });

// reset cor
doc.setTextColor(0, 0, 0);

y += 18;

  y += 15;
  doc.setFontSize(11);
  doc.text("CRITÉRIOS DE AVALIAÇÃO", 10, y);

  y += 8;

  function barra(yPos, cor, texto) {
    doc.setFillColor(...cor);
    doc.rect(10, yPos, 40, 6, "F");
    doc.text(texto, 55, yPos + 5);
  }
  
  if (y > 230) {
  doc.addPage();
  y = 20;
}

  barra(y, [34, 197, 94], "BOM (0% a 9%)");
  y += 10;
  barra(y, [245, 158, 11], "REGULAR (10% a 20%)");
  y += 10;
  barra(y, [239, 68, 68], "RUIM (>20%)");

  // ===== ESPAÇO FINAL ORGANIZADO =====
// 🔥 CORREÇÃO: GARANTE QUE TEM ESPAÇO
if (y > 230) {
  doc.addPage();
  y = 20;
}

// ESPAÇO CONTROLADO
y += 25;

// DATA
doc.setFontSize(11);
doc.text("Data: ____/____/______", 105, y, { align: "center" });

y += 15;

// LINHAS
doc.line(20, y, 90, y);
doc.line(110, y, 180, y);

y += 6;

// NOMES
doc.setFontSize(10);
doc.text("Responsável da Unidade", 25, y);
doc.text("Consultora Quality", 115, y);

  doc.save("checklist-final.pdf");
}
